css:
.mrn-wrap {
  font-size: 10pt;
  font-family: sans-serif;
}
.mrn-wrap h2 {
  margin: 0 0 6px 0;
  font-size: 14pt;
}
.mrn-meta {
  width: 100%;
  margin-bottom: 10px;
  border-collapse: collapse;
}
.mrn-meta td {
  padding: 2px 6px;
  vertical-align: top;
}
table.mrn-table {
  width: 100%;
  border-collapse: collapse;
  margin-top: 6px;
}
table.mrn-table th,
table.mrn-table td {
  border: 1px solid #000;
  padding: 3px 5px;
}
table.mrn-table th {
  background-color: #f0f0f0;
  font-size: 9pt;
}
.text-right {
  text-align: right;
}
.mrn-totals {
  margin-top: 4px;
  text-align: right;
  font-weight: bold;
}
.mrn-sig-table {
  width: 100%;
  margin-top: 40px;
  border-collapse: collapse;
}
.mrn-sig-table td {
  width: 50%;
  vertical-align: top;
  padding: 0 10px 0 0;
  border: none;
}
.mrn-sig-line {
  border-top: 1px solid #000;
  margin-top: 30px;
  padding-top: 4px;
  font-size: 9pt;
}
@media print {
  @page {
    size: A4 portrait;
    margin: 12mm;
  }
}
@media screen {
  .print-format {
    width: 180mm;
    padding: 5mm;
  }
  .mrn-wrap {
    font-size: 9pt;
  }
}
